{
  "name": "wellspring",
  "private": true,
  "scripts": {
    "dev": "pnpm --parallel --filter @wellspring/backend --filter @wellspring/frontend run dev",
    "test": "pnpm -r run test",
    "db:migrate": "pnpm --filter @wellspring/backend run db:migrate",
    "db:seed": "pnpm --filter @wellspring/backend run db:seed"
  },
  "packageManager": "pnpm@9.15.0"
}

/** @type {import('jest').Config} */
module.exports = {
  testEnvironment: "node",
  roots: ["<rootDir>/tests"],
  testMatch: ["**/*.test.ts"],
  clearMocks: true,
  passWithNoTests: true,
  transform: {
    "^.+\\.ts$": [
      "ts-jest",
      {
        tsconfig: "<rootDir>/tsconfig.test.json"
      }
    ]
  },
  moduleFileExtensions: ["ts", "js", "json"]
};

{
  "extends": "./tsconfig.json",
  "compilerOptions": {
    "rootDir": ".",
    "noEmit": true
  },
  "include": ["src/**/*.ts", "tests/**/*.ts", "prisma/**/*.ts"]
}

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

// Models are added via migrations only — see rubric.

import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient();

async function main() {
  // Seed: 2 creators, 3 programs each, ~10 sessions per program (rubric).
}

main()
  .then(async () => {
    await prisma.$disconnect();
  })
  .catch(async (e) => {
    console.error(e);
    await prisma.$disconnect();
    process.exit(1);
  });

import express from "express";
import pino from "pino";
import pinoHttp from "pino-http";

const logger = pino({ level: process.env.LOG_LEVEL ?? "info" });
const app = express();

app.use(
  pinoHttp({
    logger,
    customProps: () => ({
      request_id: undefined,
      tenant_id: undefined
    })
  })
);

app.get("/health", (_req, res) => {
  res.json({ ok: true });
});

const port = Number(process.env.PORT ?? 4000);
app.listen(port, () => {
  logger.info({ port }, "backend listening");
});

